import React, { useState } from 'react';
import './RecommendCard.css';

export default function RecommendCard({ book, delay = 0 }) {
  const [feedback, setFeedback] = useState(null);
  const [sending, setSending] = useState(false);
  const [loaded, setLoaded] = useState(false);

  const sendFeedback = async (action) => {
    if (sending) return;
    setSending(true);
    try {
      await fetch('/api/feedback', {
        method: 'POST',
        credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ book: book.title, action }),
      });
      setFeedback(action);
    } finally {
      setSending(false);
    }
  };

  const fillWidth = Math.min(book.final, 100);

  return (
    <div className="rec-card fade-up" style={{ animationDelay: `${delay}ms` }}>
      <div className="rec-card__img-wrap">
        {!loaded && <div className="skeleton rec-card__skeleton" />}
        <img
          src={book.image}
          alt={book.title}
          onLoad={() => setLoaded(true)}
          style={{ opacity: loaded ? 1 : 0 }}
        />
      </div>

      <div className="rec-card__body">
        <p className="rec-card__author">{book.author}</p>
        <h3 className="rec-card__title">{book.title}</h3>

        <p className="rec-card__why">💡 {book.why}</p>

        {/* Score bar */}
        <div className="rec-card__score">
          <div className="rec-card__score-label">
            <span>Match Score</span>
            <strong>{book.final}%</strong>
          </div>
          <div className="score-bar">
            <div className="score-fill" style={{ width: `${fillWidth}%` }} />
          </div>
          <div className="rec-card__breakdown">
            <span>Base: {book.base}%</span>
            <span>Feedback: {book.feedback > 0 ? '+' : ''}{book.feedback}</span>
            <span>Popularity: +{book.popularity}</span>
          </div>
        </div>

        {/* Feedback buttons */}
        <div className="rec-card__actions">
          <button
            className={`rec-btn rec-btn--like ${feedback === 'like' ? 'rec-btn--active' : ''}`}
            onClick={() => sendFeedback('like')}
            disabled={!!feedback || sending}
          >
            👍 Like
          </button>
          <button
            className={`rec-btn rec-btn--dislike ${feedback === 'dislike' ? 'rec-btn--active' : ''}`}
            onClick={() => sendFeedback('dislike')}
            disabled={!!feedback || sending}
          >
            👎 Dislike
          </button>
          {feedback && (
            <span className="rec-feedback-confirm">
              {feedback === 'like' ? "✓ Noted! We'll show more like this." : "✓ Got it! We'll adjust your results."}
            </span>
          )}
        </div>
      </div>
    </div>
  );
}
